// Вход от AI Agent: { chat_id, service_code, date (YYYY-MM-DD), time (HH:MM) }
const i = $input.first().json;
const chatId = Number(i.chat_id || i.chatId);
const serviceCode = String(i.service_code || '').trim();
const date = String(i.date || '').trim();
const time = String(i.time || '').trim();

if (!chatId) throw new Error('chat_id required');
if (!/^[a-z0-9_]+$/i.test(serviceCode)) throw new Error('invalid service_code');
if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) throw new Error('date must be YYYY-MM-DD');
if (!/^\d{2}:\d{2}$/.test(time)) throw new Error('time must be HH:MM');

const startsAt = new Date(`${date}T${time}:00`);
if (isNaN(+startsAt)) throw new Error('invalid date/time');
if (startsAt < new Date()) throw new Error('cannot book in the past');

return [{
  json: { chatId, serviceCode, startsAt: startsAt.toISOString(), date, time }
}];

const r = $input.first().json;
if (!r || !r.id) {
  return [{ json: { ok: false, message: 'не получилось сохранить запись (клиент или услуга не найдены)' } }];
}
return [{
  json: {
    ok: true,
    bookingId: r.id,
    message: `Запись создана. Дата: ${new Date(r.starts_at).toLocaleString('ru-RU')}.`
  }
}];
